1	//! Wake word keyword spotting using `sherpa-onnx`.
2	//!
3	//! Constraints:
4	//! - Uses only local model artifacts from config (no downloads, no network).
5	//! - Runs on an OS thread (never in CPAL callback, never on Tokio).
6	//! - Emits wake status via `tracing` (stderr). Never writes wake-related data to stdout.
7	
8	use anyhow::{anyhow, Context, Result};
9	use std::path::Path;
10	
11	use crate::config::WakeConfig;
12	
13	/// Thin wrapper around sherpa-onnx keyword spotting state for one audio stream.
14	pub struct WakeWord {
15	    kws: sherpa_onnx::KeywordSpotter,
16	    stream: sherpa_onnx::OnlineStream,
17	}
18	
19	impl WakeWord {
20	    pub fn new(cfg: &WakeConfig) -> Result<Self> {
21	        if !cfg.enabled {
22	            return Err(anyhow!("wake is disabled"));
23	        }
24	
25	        let encoder = cfg
26	            .encoder
27	            .as_ref()
28	            .context("wake.encoder is required when wake.enabled=true")?;
29	        let decoder = cfg
30	            .decoder
31	            .as_ref()
32	            .context("wake.decoder is required when wake.enabled=true")?;
33	        let joiner = cfg
34	            .joiner
35	            .as_ref()
36	            .context("wake.joiner is required when wake.enabled=true")?;
37	        let tokens = cfg
38	            .tokens
39	            .as_ref()
40	            .context("wake.tokens is required when wake.enabled=true")?;
41	        let keywords = cfg
42	            .keywords
43	            .as_ref()
44	            .context("wake.keywords is required when wake.enabled=true")?;
45	
46	        let mut config = sherpa_onnx::KeywordSpotterConfig::default();
47	        config.model_config.transducer.encoder = Some(encoder.to_string_lossy().to_string());
48	        config.model_config.transducer.decoder = Some(decoder.to_string_lossy().to_string());
49	        config.model_config.transducer.joiner = Some(joiner.to_string_lossy().to_string());
50	        config.model_config.tokens = Some(tokens.to_string_lossy().to_string());
51	        config.keywords_file = Some(keywords.to_string_lossy().to_string());
52	
53	        // Gigaspeech (and other BPE) KWS bundles ship `bpe.model` next to the ONNX
54	        // files. Sherpa requires `modeling_unit` + `bpe_vocab` for those; if the file
55	        // exists beside `encoder.onnx`, enable BPE automatically (no extra config key).
56	        let enc_path = Path::new(encoder);
57	        if let Some(dir) = enc_path.parent() {
58	            let bpe = dir.join("bpe.model");
59	            if bpe.is_file() {
60	                config.model_config.modeling_unit = Some("bpe".to_string());
61	                config.model_config.bpe_vocab = Some(bpe.to_string_lossy().to_string());
62	            }
63	        }
64	
65	        let kws = sherpa_onnx::KeywordSpotter::create(&config)
66	            .ok_or_else(|| anyhow!("Failed to create sherpa-onnx KeywordSpotter"))?;
67	        let stream = kws.create_stream();
68	
69	        Ok(Self { kws, stream })
70	    }
71	
72	    /// Feed audio samples (16kHz mono f32) into the spotter.
73	    ///
74	    /// Returns `Some(keyword)` when a keyword is detected. Callers typically start a
75	    /// LISTENING window and then `reset()` the spotter state to avoid repeated triggers.
76	    pub fn accept_audio(&self, sample_rate_hz: i32, audio: &[f32]) {
77	        self.stream.accept_waveform(sample_rate_hz, audio);
78	    }
79	
80	    /// Run decode steps until the stream is no longer ready.
81	    pub fn decode_until_not_ready(&self) {
82	        while self.kws.is_ready(&self.stream) {
83	            self.kws.decode(&self.stream);
84	        }
85	    }
86	
87	    /// Read the current result and return the detected keyword (if any).
88	    pub fn take_keyword(&self) -> Option<String> {
89	        let res = self.kws.get_result(&self.stream)?;
90	        if res.keyword.trim().is_empty() {
91	            None
92	        } else {
93	            Some(res.keyword)
94	        }
95	    }
96	
97	    pub fn reset(&self) {
98	        self.kws.reset(&self.stream);
99	    }
100	}
