1	//! Wake word (keyword spotter) smoke test harness (Phase 2).
2	//!
3	//! This test is skipped by default so that `cargo test -q` stays green without
4	//! local model artifacts present.
5	//!
6	//! Run with:
7	//! `RUN_KWS_TESTS=1 KWS_ENCODER=... KWS_DECODER=... KWS_JOINER=... KWS_TOKENS=... KWS_KEYWORDS=... cargo test --test wake_word -- --include-ignored`
8	
9	use std::path::Path;
10	
11	fn should_run_kws() -> bool {
12	    std::env::var("RUN_KWS_TESTS")
13	        .map(|v| v == "1")
14	        .unwrap_or(false)
15	}
16	
17	fn env_path(name: &str) -> String {
18	    let v = std::env::var(name).unwrap_or_else(|_| panic!("Missing env var {name}"));
19	    assert!(Path::new(&v).exists(), "{name} does not exist: {v}");
20	    v
21	}
22	
23	#[test]
24	#[ignore = "heavy wake-word test — set RUN_KWS_TESTS=1 and KWS_* paths"]
25	fn keyword_spotter_loads_and_decodes_silence() {
26	    if !should_run_kws() {
27	        return;
28	    }
29	
30	    let encoder = env_path("KWS_ENCODER");
31	    let decoder = env_path("KWS_DECODER");
32	    let joiner = env_path("KWS_JOINER");
33	    let tokens = env_path("KWS_TOKENS");
34	    let keywords = env_path("KWS_KEYWORDS");
35	
36	    let mut config = sherpa_onnx::KeywordSpotterConfig::default();
37	    config.model_config.transducer.encoder = Some(encoder);
38	    config.model_config.transducer.decoder = Some(decoder);
39	    config.model_config.transducer.joiner = Some(joiner);
40	    config.model_config.tokens = Some(tokens);
41	    config.keywords_file = Some(keywords);
42	
43	    let kws = sherpa_onnx::KeywordSpotter::create(&config)
44	        .expect("create keyword spotter (check model paths)");
45	    let stream = kws.create_stream();
46	
47	    // 1 second of silence @ 16kHz. We just want to validate the decode loop doesn't crash.
48	    let audio = vec![0.0f32; 16_000];
49	    stream.accept_waveform(16_000, &audio);
50	    stream.input_finished();
51	
52	    while kws.is_ready(&stream) {
53	        kws.decode(&stream);
54	    }
55	
56	    // It's fine if there's no trigger; we only care that the decode path works.
57	    let _ = kws.get_result(&stream);
58	    let _ = kws.get_result_as_json(&stream);
59	}
